#creating Age Group column:

#CREATE DIFFERENT CATEGORY OF AGE
def categorize_age(age):
    if age<=17:
        return '0-17'
    elif age<=25:
        return '18-25'
    elif age<=35:
        return '26-35'
    elif age<=45:
        return '36-45'
    elif age<=50:
        return '46-50'
    elif age<=55:
        return '51-55'
    else:return '55+'

#apply the function to create a new column 'age_group'
df['Age_Group']=df['Age'].apply(categorize_age)
print(df)
